import { useState, useEffect } from 'react';
import api from '../services/api';

const TaskForm = ({ onTaskCreated }) => {
  const [title, setTitle] = useState('');
  const [deadline, setDeadline] = useState('');
  const [assignedTo, setAssignedTo] = useState('');
  const [members, setMembers] = useState([]); // List of members from DB

  useEffect(() => {
    const fetchMembers = async () => {
      try {
        const res = await api.get('/auth/users');
        setMembers(res.data);
      } catch (err) {
        console.error('Failed to load members');
      }
    };
    fetchMembers();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!assignedTo) return alert('Please select a member');
    
    try {
      await api.post('/tasks', { 
        title, 
        deadline, 
        assignedTo, 
        project: 'General Project' 
      });
      
      setTitle('');
      setDeadline('');
      setAssignedTo('');
      if (onTaskCreated) onTaskCreated();
    } catch (err) {
      alert('Failed to create task.');
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr auto', gap: '10px', alignItems: 'end' }}>
      <div>
        <label style={{ fontSize: '0.75rem', fontWeight: '600', color: '#64748b' }}>TASK TITLE</label>
        <input 
          type="text" 
          placeholder="Task Name" 
          value={title} 
          onChange={(e) => setTitle(e.target.value)} 
          required 
          style={{ margin: '5px 0 0 0' }}
        />
      </div>
      <div>
        <label style={{ fontSize: '0.75rem', fontWeight: '600', color: '#64748b' }}>DEADLINE</label>
        <input 
          type="date" 
          value={deadline} 
          onChange={(e) => setDeadline(e.target.value)} 
          required 
          style={{ margin: '5px 0 0 0' }}
        />
      </div>
      <div>
        <label style={{ fontSize: '0.75rem', fontWeight: '600', color: '#64748b' }}>ASSIGN TO</label>
        <select 
          value={assignedTo} 
          onChange={(e) => setAssignedTo(e.target.value)} 
          required
          style={{ margin: '5px 0 0 0' }}
        >
          <option value="">Select Member</option>
          {members.map(user => (
            <option key={user._id} value={user._id}>{user.name}</option>
          ))}
        </select>
      </div>
      <button type="submit" style={{ height: '42px', padding: '0 20px' }}>
        Assign
      </button>
    </form>
  );
};

export default TaskForm;
